SELECT COUNT(*) 
FROM bim_objects 
WHERE status = 'Draft';

SELECT name, status 
FROM bim_objects 
WHERE status = 'Approved';

SELECT object_type, status, MIN(creation_date) AS earliest_creation_date
FROM bim_objects
GROUP BY object_type, status;

SELECT name
FROM bim_objects
WHERE object_id = 1;
